def _get_credential():
    """Return a token credential backed by Managed Identity (preferred) or
    the default credential chain for local development."""
    if MANAGED_IDENTITY_CLIENT_ID:
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
