_eventgrid_client: Optional[EventGridPublisherClient] = None


def get_credential():
    global _credential
    if _credential is None:
        _credential = _get_credential()
    return _credential


def get_blob_service_client() -> BlobServiceClient:
    """Blob client authenticated via Managed Identity.
    Required role on the storage account: **Storage Blob Data Contributor**."""
    global _blob_service_client
    if _blob_service_client is None:
        _blob_service_client = BlobServiceClient(
            account_url=STORAGE_ACCOUNT_URL,
            credential=get_credential(),
        )
    return _blob_service_client


def get_cosmos_container():
    """Cosmos DB container client authenticated via Managed Identity.
    Required role on the Cosmos account: **Cosmos DB Built-in Data Contributor**
    (or at minimum Cosmos DB Account Contributor for control-plane + RBAC data
    actions)."""
    global _cosmos_client
    if _cosmos_client is None:
        _cosmos_client = CosmosClient(
            url=COSMOS_ENDPOINT,
            credential=get_credential(),
        )
    database = _cosmos_client.get_database_client(COSMOS_DATABASE)
    container = database.get_container_client(COSMOS_CONTAINER)
    return container


def get_eventgrid_client() -> EventGridPublisherClient:
    """Event Grid publisher authenticated via Managed Identity.
    Required role on the Event Grid topic: **Event Grid Data Sender**."""
    global _eventgrid_client
    if _eventgrid_client is None:
        _eventgrid_client = EventGridPublisherClient(
            endpoint=EVENT_GRID_TOPIC_ENDPOINT,
            credential=get_credential(),
        )
    return _eventgrid_client


