def process_blob_content(blob_name: str, raw_content: bytes) -> Dict[str, Any]:
    """Transform / analyse the raw blob content and return a result dict.

    Replace this stub with your actual business logic (parsing CSV, running
    ML inference, validating JSON, etc.).
    """
    text = raw_content.decode("utf-8", errors="replace")
    line_count = text.count("\n") + (1 if text and not text.endswith("\n") else 0)
    word_count = len(text.split())

    return {
        "blob_name": blob_name,
        "size_bytes": len(raw_content),
        "line_count": line_count,
        "word_count": word_count,
        "snippet": text[:500],
        "status": "processed",
    }


def write_result_to_cosmos(result: Dict[str, Any]) -> Dict[str, Any]:
    """Persist the processing result to Cosmos DB."""
    container = get_cosmos_container()

    document = {
        "id": f"{result['blob_name']}-{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}",
        "partitionKey": result["blob_name"],
        "processedAt": datetime.datetime.utcnow().isoformat() + "Z",
        **result,
    }

    created = container.upsert_item(body=document)
    logging.info("Cosmos document created: %s", created["id"])
    return created


def send_event_grid_notification(result: Dict[str, Any], cosmos_id: str) -> None:
    """Publish a CloudEvent to Event Grid so downstream consumers are notified."""
    client = get_eventgrid_client()

    event = CloudEvent(
        type="BlobProcessing.Completed",
        source=f"/functions/blob-processor/{result['blob_name']}",
        data={
            "cosmosDocumentId": cosmos_id,
            "blobName": result["blob_name"],
            "status": result["status"],
            "sizeBytes": result["size_bytes"],
            "processedAt": datetime.datetime.utcnow().isoformat() + "Z",
        },
        subject=result["blob_name"],
    )

    client.send([event])
    logging.info("Event Grid notification sent for blob: %s", result["blob_name"])


def move_blob_to_processed(blob_name: str) -> None:
    """Copy the blob to the processed container and delete the original."""
    svc = get_blob_service_client()
    source_blob = svc.get_blob_client(STORAGE_CONTAINER_INPUT, blob_name)
    dest_blob = svc.get_blob_client(STORAGE_CONTAINER_PROCESSED, blob_name)

    dest_blob.start_copy_from_url(source_blob.url)
    source_blob.delete_blob()
    logging.info("Blob moved to processed container: %s", blob_name)


