# 1. Blob-triggered function – fires automatically when a new blob lands
# ---------------------------------------------------------------------------
@app.blob_trigger(
    arg_name="inputblob",
    path=f"{STORAGE_CONTAINER_INPUT}/{{name}}",
    connection="AzureWebJobsStorage",  # or use MI-based connection string-less binding
)
def blob_trigger_processor(inputblob: func.InputStream):
    """Triggered when a new blob is uploaded to the input container."""
    blob_name = inputblob.name or "unknown"
    logging.info("Blob trigger fired – processing: %s (%d bytes)", blob_name, inputblob.length or 0)

    try:
        raw_content = inputblob.read()

        # Step 1: Process
        result = process_blob_content(blob_name, raw_content)

        # Step 2: Persist to Cosmos DB
        cosmos_doc = write_result_to_cosmos(result)

        # Step 3: Notify via Event Grid
        send_event_grid_notification(result, cosmos_doc["id"])

        # Step 4: Move blob to processed container
        # Extract just the file name (path may include container prefix)
        simple_name = blob_name.split("/")[-1]
        move_blob_to_processed(simple_name)

        logging.info("Successfully processed blob: %s", blob_name)

    except Exception:
        logging.exception("Error processing blob: %s", blob_name)
        raise


# 2. HTTP-triggered function – on-demand processing of a named blob
# ---------------------------------------------------------------------------
@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """POST /api/process  { "blob_name": "myfile.csv" }

    Reads the specified blob from the input container, processes it, writes
    results to Cosmos DB, and sends an Event Grid notification.
    """
    try:
        body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON body. Expected {\"blob_name\": \"...\"}"}),
            status_code=400,
            mimetype="application/json",
        )

    blob_name = body.get("blob_name")
    if not blob_name:
        return func.HttpResponse(
            json.dumps({"error": "Missing 'blob_name' in request body."}),
            status_code=400,
            mimetype="application/json",
        )

    logging.info("HTTP trigger – processing blob: %s", blob_name)

    try:
        # Download blob via Managed Identity
        svc = get_blob_service_client()
        blob_client = svc.get_blob_client(STORAGE_CONTAINER_INPUT, blob_name)
        raw_content = blob_client.download_blob().readall()

        # Process
        result = process_blob_content(blob_name, raw_content)

        # Persist
        cosmos_doc = write_result_to_cosmos(result)

        # Notify
        send_event_grid_notification(result, cosmos_doc["id"])

        # Move
        move_blob_to_processed(blob_name)

        response_body = {
            "message": "Blob processed successfully.",
            "cosmosDocumentId": cosmos_doc["id"],
            "result": result,
        }
        return func.HttpResponse(
            json.dumps(response_body, default=str),
            status_code=200,
            mimetype="application/json",
        )

    except Exception as exc:
        logging.exception("Error processing blob via HTTP trigger: %s", blob_name)
        return func.HttpResponse(
            json.dumps({"error": str(exc)}),
            status_code=500,
            mimetype="application/json",
        )


# 3. Timer-triggered function – periodic sweep of unprocessed blobs
# ---------------------------------------------------------------------------
@app.timer_trigger(
    schedule="0 */30 * * * *",  # every 30 minutes
    arg_name="timer",
    run_on_startup=False,
)
def timer_trigger_sweep(timer: func.TimerRequest):
    """Periodically scan the input container for any blobs that were missed
    by the blob trigger (e.g. due to transient failures)."""
    if timer.past_due:
        logging.warning("Timer trigger is past due – running catch-up sweep.")

    logging.info("Timer sweep started.")
    svc = get_blob_service_client()
    container_client = svc.get_container_client(STORAGE_CONTAINER_INPUT)

    processed_count = 0
    error_count = 0

    for blob_properties in container_client.list_blobs():
        blob_name = blob_properties.name
        logging.info("Sweep – processing blob: %s", blob_name)
        try:
            blob_client = container_client.get_blob_client(blob_name)
            raw_content = blob_client.download_blob().readall()

            result = process_blob_content(blob_name, raw_content)
            cosmos_doc = write_result_to_cosmos(result)
            send_event_grid_notification(result, cosmos_doc["id"])
            move_blob_to_processed(blob_name)

            processed_count += 1
        except Exception:
            logging.exception("Sweep – error processing blob: %s", blob_name)
            error_count += 1

    logging.info("Timer sweep complete. Processed: %d, Errors: %d", processed_count, error_count)


