@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Simple liveness / readiness probe."""
    health: Dict[str, Any] = {
        "status": "healthy",
        "timestamp": datetime.datetime.utcnow().isoformat() + "Z",
        "checks": {},
    }

    # Check Blob Storage connectivity
    try:
        svc = get_blob_service_client()
        svc.get_account_information()
        health["checks"]["blob_storage"] = "ok"
    except Exception as exc:
        health["checks"]["blob_storage"] = f"error: {exc}"
        health["status"] = "degraded"

    # Check Cosmos DB connectivity
    try:
        container = get_cosmos_container()
        # A lightweight read – query for zero items
        list(container.query_items("SELECT TOP 1 c.id FROM c", enable_cross_partition_query=True, max_item_count=1))
        health["checks"]["cosmos_db"] = "ok"
    except Exception as exc:
        health["checks"]["cosmos_db"] = f"error: {exc}"
        health["status"] = "degraded"

    status_code = 200 if health["status"] == "healthy" else 503
    return func.HttpResponse(
        json.dumps(health, default=str),
        status_code=status_code,
        mimetype="application/json",
    )


